// Basic line trace from camera
FHitResult Hit;
FVector Start = CameraComponent->GetComponentLocation();
FVector End = Start + CameraComponent->GetForwardVector() * 5000.f;

FCollisionQueryParams Params;
Params.AddIgnoredActor(this);
Params.bTraceComplex = true;

bool bHit = GetWorld()->LineTraceSingleByChannel(
    Hit, Start, End, ECC_Visibility, Params
);

if (bHit) {
    AActor* HitActor = Hit.GetActor();
    FVector HitLocation = Hit.ImpactPoint;
    FVector HitNormal = Hit.ImpactNormal;
    UPrimitiveComponent* HitComp = Hit.GetComponent();

    // Spawn decal at hit point
    DrawDebugPoint(GetWorld(), HitLocation, 10.f, FColor::Red, false, 5.f);
}

// Sphere sweep for melee attack
FHitResult Hit;
FVector Start = GetActorLocation();
FVector End = Start + GetActorForwardVector() * 200.f;
FCollisionShape Shape = FCollisionShape::MakeSphere(50.f);

FCollisionQueryParams Params;
Params.AddIgnoredActor(this);

bool bHit = GetWorld()->SweepSingleByChannel(
    Hit, Start, End, FQuat::Identity,
    ECC_Pawn, Shape, Params
);

if (bHit) {
    if (ACharacter* Enemy = Cast<ACharacter>(Hit.GetActor())) {
        UGameplayStatics::ApplyDamage(Enemy, 30.f, GetController(), this, nullptr);
    }
}

// Debug visualization
DrawDebugSphere(GetWorld(), Start, 50.f, 12, FColor::Green, false, 2.f);
DrawDebugSphere(GetWorld(), End, 50.f, 12, FColor::Red, false, 2.f);

// Using FHitResult for a shooting system
void AMyWeapon::Fire() {
    FHitResult Hit;
    FVector Start = MuzzleLocation;
    FVector End = Start + AimDirection * Range;

    if (GetWorld()->LineTraceSingleByChannel(Hit, Start, End, ECC_Visibility)) {
        // What did we hit?
        AActor* HitActor = Hit.GetActor();
        FVector HitPoint = Hit.ImpactPoint;
        FVector HitNormal = Hit.ImpactNormal;

        // Headshot detection
        if (Hit.BoneName == "head") {
            Damage *= 2.f;
        }

        // Surface-specific effects
        if (Hit.PhysMaterial.IsValid()) {
            SpawnSurfaceEffect(Hit.PhysMaterial.Get(), HitPoint, HitNormal);
        }

        // Spawn decal aligned to surface
        FRotator DecalRot = HitNormal.Rotation();
        SpawnDecal(HitPoint, DecalRot);

        // Apply damage
        if (HitActor) {
            UGameplayStatics::ApplyPointDamage(HitActor, Damage, AimDirection,
                Hit, GetOwner()->GetInstigatorController(), GetOwner(), DamageTypeClass);
        }
    }
}

// Setup collision in constructor
AMyPickup::AMyPickup() {
    SphereComp = CreateDefaultSubobject<USphereComponent>(TEXT("Sphere"));
    SetRootComponent(SphereComp);

    // Only detect overlaps with Pawns, ignore everything else
    SphereComp->SetCollisionEnabled(ECollisionEnabled::QueryOnly);
    SphereComp->SetCollisionResponseToAllChannels(ECR_Ignore);
    SphereComp->SetCollisionResponseToChannel(ECC_Pawn, ECR_Overlap);
    SphereComp->SetGenerateOverlapEvents(true);
}

// Or use a preset
MeshComp->SetCollisionProfileName(TEXT("BlockAllDynamic"));

