// Pickup with overlap detection
void AMyPickup::BeginPlay() {
    Super::BeginPlay();
    SphereComp->OnComponentBeginOverlap.AddDynamic(this, &AMyPickup::OnOverlap);
}

void AMyPickup::OnOverlap(UPrimitiveComponent* OverlappedComp, AActor* OtherActor,
    UPrimitiveComponent* OtherComp, int32 OtherBodyIndex,
    bool bFromSweep, const FHitResult& SweepResult) {

    if (AMyCharacter* Player = Cast<AMyCharacter>(OtherActor)) {
        Player->AddItem(ItemData);
        Destroy();
    }
}

// Hit event for physics collision
void AMyActor::BeginPlay() {
    MeshComp->OnComponentHit.AddDynamic(this, &AMyActor::OnHit);
}

void AMyActor::OnHit(UPrimitiveComponent* HitComp, AActor* OtherActor,
    UPrimitiveComponent* OtherComp, FVector NormalImpulse, const FHitResult& Hit) {
    // Physics collision occurred
}

// Launch a physics projectile
void AMyProjectile::Fire(FVector Direction, float Force) {
    MeshComp->SetSimulatePhysics(true);
    MeshComp->SetEnableGravity(true);
    MeshComp->AddImpulse(Direction * Force);
}

// Explosive force on nearby actors
void AMyExplosion::Explode() {
    TArray<FHitResult> Hits;
    FCollisionShape Shape = FCollisionShape::MakeSphere(500.f);
    GetWorld()->SweepMultiByChannel(Hits, GetActorLocation(), GetActorLocation(),
        FQuat::Identity, ECC_PhysicsBody, Shape);

    for (auto& Hit : Hits) {
        if (UPrimitiveComponent* Comp = Hit.GetComponent()) {
            if (Comp->IsSimulatingPhysics()) {
                FVector Dir = (Hit.ImpactPoint - GetActorLocation()).GetSafeNormal();
                Comp->AddImpulse(Dir * 50000.f);
            }
        }
    }
}
